#include <stdio.h>

#define MOD 1000000007

long long fast_power(long long base, long long exp) {
    long long res = 1;
    while (exp > 0) {
        if (exp % 2 == 1) {
            res = (res * base) % MOD;
        }
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

int main() {
    long long n;
    scanf("%lld", &n);
    long long res = (fast_power(2, 2*n-1) + fast_power(2, n-1)) % MOD;
    printf("%lld\n", n == 0 ? 1 : res);
    return 0;
}
